# --- Validation pipeline ---


def validate_structure(data):
    """Check submission is a dict with 'components' key."""
    if not isinstance(data, dict):
        raise ValueError("Submission must be a JSON object")
    if "components" not in data:
        raise ValueError("Missing 'components' key")
    return data["components"]


def validate_count(components):
    """Check exactly REQUIRED_COMPONENTS components."""
    if not isinstance(components, list):
        raise ValueError("'components' must be an array")
    if len(components) != REQUIRED_COMPONENTS:
        raise ValueError(
            f"Expected exactly {REQUIRED_COMPONENTS} components, got {len(components)}"
        )
    return components


def validate_and_parse(components):
    """Validate fields, ranges, and parse into (freq, amplitude, phase) tuples."""
    parsed = []
    for i, comp in enumerate(components):
        if not isinstance(comp, dict):
            raise ValueError(f"Component {i} must be an object")

        for key in ("freq", "amplitude", "phase"):
            if key not in comp:
                raise ValueError(f"Component {i} missing '{key}'")

        try:
            freq = float(comp["freq"])
            amplitude = float(comp["amplitude"])
            phase = float(comp["phase"])
        except (TypeError, ValueError) as e:
            raise ValueError(f"Component {i} has non-numeric value: {e}")

        if not (FREQ_MIN <= freq <= FREQ_MAX):
            raise ValueError(
                f"Component {i}: freq {freq} out of range [{FREQ_MIN}, {FREQ_MAX}]"
            )
        if not (AMP_MIN <= amplitude <= AMP_MAX):
            raise ValueError(
                f"Component {i}: amplitude {amplitude} out of range [{AMP_MIN}, {AMP_MAX}]"
            )
        if not (PHASE_MIN <= phase <= PHASE_MAX + 0.001):
            raise ValueError(
                f"Component {i}: phase {phase} out of range [{PHASE_MIN}, {PHASE_MAX:.6f}]"
            )

        parsed.append((freq, amplitude, phase))

    return parsed


# --- Scoring ---


def compute_rms_error(submission_harmonics):
    """Compute RMS error between submission and target sample points."""
    sum_sq_error = 0.0

    for i in range(NUM_SAMPLES):
        t = SAMPLE_T[i]
        target_val = SAMPLE_Y[i]
        submit_val = 0.0
        for freq, amplitude, phase in submission_harmonics:
            submit_val += amplitude * math.sin(freq * t + phase)
        diff = target_val - submit_val
        sum_sq_error += diff * diff

    mse = sum_sq_error / NUM_SAMPLES
    return round(math.sqrt(mse), SCORE_PRECISION)


# --- Main ---


def main():
    submission_file = os.environ.get("SUBMISSION_FILE", "/eval/submission.json")

    # Read submission
    try:
        with open(submission_file, "r") as f:
            data = json.load(f)
    except FileNotFoundError:
        print(f"Submission file not found: {submission_file}", file=sys.stderr)
        print(f"SCORE: {PENALTY_SCORE}")
        sys.exit(0)
    except json.JSONDecodeError as e:
        print(f"Invalid JSON: {e}", file=sys.stderr)
        print(f"SCORE: {PENALTY_SCORE}")
        sys.exit(0)

    # Validate (fail-fast pipeline)
    try:
        components = validate_structure(data)
        components = validate_count(components)
        submission_harmonics = validate_and_parse(components)
    except ValueError as e:
        print(f"Validation error: {e}", file=sys.stderr)
        print(f"SCORE: {PENALTY_SCORE}")
        sys.exit(0)

    # Score
    try:
        rms = compute_rms_error(submission_harmonics)
    except Exception as e:
        print(f"Scoring error: {e}", file=sys.stderr)
        print(f"SCORE: {PENALTY_SCORE}")
        sys.exit(0)

    # Diagnostics
    print(f"Waveform Synthesis Eval")
    print(f"Sample points: {NUM_SAMPLES}")
    print(f"Submission components: {REQUIRED_COMPONENTS}")
    print(f"RMS error: {rms}")
    print(f"SCORE: {rms}")


if __name__ == "__main__":
    main()
